package main

import "fmt"

// primes returns all prime numbers <= n using the Sieve of Eratosthenes.
func primes(n int) []int {
	if n < 2 {
		return nil
	}
	composite := make([]bool, n+1)
	var result []int
	for i := 2; i <= n; i++ {
		if composite[i] {
			continue
		}
		result = append(result, i)
		for j := i * i; j <= n; j += i {
			composite[j] = true
		}
	}
	return result
}

func main() {
	fmt.Println(primes(30))
}
```

